    if is_disaster:
        # Get base name by removing disaster suffixes
        base_name = project_name
        for suffix in [' (FEMA Project)', ' (CalOES Project)', ' (CalJPIA Project)', ' (FEMA/CalOES Project)', ' (CalOES Project)']:
